using System.Collections;
using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Orquestra a lista de ataques de um inimigo (Enemy Creator — Etapa 2.1).
///
/// Enquanto <see cref="EnemyController.State"/> for Perseguindo, escolhe (a cada
/// frame, em <see cref="Update"/>) o ataque com maior <see cref="EnemyAttack.priority"/>
/// entre os que estiverem disponíveis (<see cref="EnemyAttack.CanUse"/>) e corre o
/// ciclo completo: PreparandoAtaque (telegraph) → Atacando (Execute) →
/// Recuperando → volta a Perseguindo.
///
/// Não interfere com Idle/Alerta/Perseguindo (geridos por EnemyDetection) nem com
/// Patrulhando/VoltandoParaCasa (EnemyMovement). Durante Atacando, EnemyMovement
/// não controla o Rigidbody2D — cada <see cref="EnemyAttack.Execute"/> que precise
/// de mover o inimigo (investida, salto, ataque cima-para-baixo) fá-lo
/// directamente via <see cref="Rb"/>.
///
/// Fornece um conjunto de helpers (DamagePlayer, PushPlayer, TrapPlayer,
/// SpawnProjectile, etc) usados pelas subclasses concretas em Enemy/Attacks/,
/// reutilizando os mecanismos já existentes para o player: PlayerProgress
/// (corações), PlayerMotor2D (movimento bloqueado/knockback) e WaterDetector
/// (estado de água).
/// </summary>
[RequireComponent(typeof(EnemyController))]
public class EnemyAttackController : MonoBehaviour
{
    [Header("Ataques (Etapa 2.1)")]
    [Tooltip("Lista de ataques deste inimigo. Em cada frame de Perseguindo, escolhe o disponível (CanUse) com maior 'priority'.")]
    [SerializeReference] public List<EnemyAttack> attacks = new List<EnemyAttack>();

    [Header("Linha de Visão (Ataques)")]
    [Tooltip("Camadas que bloqueiam a linha de visão para ataques com 'requiresLineOfSight'. Vazio = vê sempre o alvo.")]
    public LayerMask lineOfSightBlockers;

    [Header("Referências (auto-detectadas se vazias)")]
    [SerializeField] private WaterDetector waterDetector;
    [SerializeField] private EnemyMovement movement;

    /// <summary>Inimigo dono deste controller.</summary>
    public EnemyController Controller => _controller;

    /// <summary>Alvo actual (atalho para EnemyController.Target — normalmente o player).</summary>
    public Transform Target => _controller.Target;

    /// <summary>Rigidbody2D do inimigo. Pode ser null em inimigos estáticos.</summary>
    public Rigidbody2D Rb => _controller.Rb;

    /// <summary>Ataque actualmente em execução (PreparandoAtaque/Atacando/Recuperando), se algum.</summary>
    public EnemyAttack CurrentAttack { get; private set; }

    private EnemyController _controller;
    private Coroutine _routine;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();

        if (waterDetector == null) waterDetector = GetComponent<WaterDetector>();
        if (movement == null) movement = GetComponent<EnemyMovement>();
    }

    /// <summary>
    /// WaterDetector resolvido de forma preguiçosa: o EnemyWaterBehavior
    /// (Etapa 3.1) pode só adicionar o WaterDetector no seu próprio Awake,
    /// depois do Awake deste controller.
    /// </summary>
    private WaterDetector WaterDetectorResolved
    {
        get
        {
            if (waterDetector == null) waterDetector = GetComponent<WaterDetector>();
            return waterDetector;
        }
    }

    private void Update()
    {
        if (_controller.IsTerminal) return;
        if (_routine != null) return;
        if (_controller.State != EnemyState.Perseguindo) return;
        if (attacks == null || attacks.Count == 0) return;

        var chosen = ChooseAttack();
        if (chosen == null) return;

        _routine = StartCoroutine(RunAttack(chosen));
    }

    private EnemyAttack ChooseAttack()
    {
        EnemyAttack best = null;

        foreach (var attack in attacks)
        {
            if (attack == null || !attack.CanUse(this)) continue;
            if (best == null || attack.priority > best.priority) best = attack;
        }

        return best;
    }

    private IEnumerator RunAttack(EnemyAttack attack)
    {
        CurrentAttack = attack;
        _controller.SetState(EnemyState.PreparandoAtaque);

        if (attack.prepTime > 0f)
            yield return new WaitForSeconds(attack.prepTime);

        if (_controller.IsTerminal)
        {
            CurrentAttack = null;
            _routine = null;
            yield break;
        }

        _controller.SetState(EnemyState.Atacando);
        yield return attack.Execute(this);

        attack.availableAt = Time.time + attack.cooldown;
        CurrentAttack = null;

        if (!_controller.IsTerminal)
        {
            _controller.SetState(EnemyState.Recuperando);

            if (attack.recoveryTime > 0f)
                yield return new WaitForSeconds(attack.recoveryTime);

            // Só volta a Perseguindo se nada (stun, dano, etc) tiver mudado o
            // estado entretanto.
            if (!_controller.IsTerminal && _controller.State == EnemyState.Recuperando)
                _controller.SetState(EnemyState.Perseguindo);
        }

        _routine = null;
    }

    // ==================== Ambiente / Selecção ====================

    /// <summary>
    /// True se o ambiente actual do inimigo (água — WaterDetector.IsInWater, ou
    /// ar — EnemyMovement.movementType Voador/Flutuante, ou chão por omissão)
    /// permitir usar "attack" (usableOnGround/InAir/InWater).
    /// </summary>
    public bool EnvironmentAllows(EnemyAttack attack)
    {
        var wd = WaterDetectorResolved;
        if (wd != null && wd.IsInWater) return attack.usableInWater;

        bool airborne = movement != null &&
            (movement.movementType == EnemyMovementType.Voador || movement.movementType == EnemyMovementType.Flutuante);

        return airborne ? attack.usableInAir : attack.usableOnGround;
    }

    /// <summary>
    /// True se a restrição de posição na água do ataque (Etapa 3.2 —
    /// SoSuperficie/SoSubmerso) for satisfeita. Ataques "Qualquer" passam
    /// sempre; as restrições exigem que o inimigo esteja em água (com
    /// WaterDetector) na profundidade certa.
    /// </summary>
    public bool WaterPositionAllows(EnemyAttack attack)
    {
        if (attack.waterPosition == WaterAttackPosition.Qualquer) return true;

        var wd = WaterDetectorResolved;
        if (wd == null || !wd.IsInWater) return false;

        return attack.waterPosition == WaterAttackPosition.SoSuperficie ? wd.IsAtSurface : wd.IsSubmerged;
    }

    /// <summary>True se não houver "lineOfSightBlockers" entre este inimigo e "target".</summary>
    public bool HasLineOfSight(Transform target)
    {
        if (target == null) return false;
        if (lineOfSightBlockers.value == 0) return true;

        var hit = Physics2D.Linecast(transform.position, target.position, lineOfSightBlockers);
        return hit.collider == null;
    }

    // ==================== Helpers para EnemyAttack.Execute ====================

    /// <summary>Distância actual ao alvo (Target). 999 se não houver alvo.</summary>
    public float DistanceToTarget()
    {
        return Target != null ? Vector2.Distance(transform.position, Target.position) : 999f;
    }

    /// <summary>Direcção (normalizada) deste inimigo para o alvo. Vector2.right se não houver alvo.</summary>
    public Vector2 DirectionToTarget()
    {
        if (Target == null) return Vector2.right;

        Vector2 d = (Vector2)Target.position - (Vector2)transform.position;
        return d.sqrMagnitude > 0.0001f ? d.normalized : Vector2.right;
    }

    /// <summary>True se o alvo (Target) estiver a "radius" ou menos de "origin".</summary>
    public bool IsTargetWithin(Vector2 origin, float radius)
    {
        return Target != null && ((Vector2)Target.position - origin).sqrMagnitude <= radius * radius;
    }

    /// <summary>True se o alvo (Target) tiver WaterDetector e estiver em água (IsInWater).</summary>
    public bool IsTargetInWater()
    {
        if (Target == null) return false;

        var wd = Target.GetComponent<WaterDetector>();
        return wd != null && wd.IsInWater;
    }

    /// <summary>True se o alvo (Target) tiver WaterDetector e estiver submerso (IsSubmerged).</summary>
    public bool IsTargetSubmerged()
    {
        if (Target == null) return false;

        var wd = Target.GetComponent<WaterDetector>();
        return wd != null && wd.IsSubmerged;
    }

    /// <summary>
    /// Move o inimigo na direcção do alvo a "speed" m/s (nado durante ataques
    /// aquáticos — ver EnemyAttack.attackSwimSpeed). Chamar a cada frame dentro
    /// de Execute. Não faz nada sem Rigidbody2D/alvo ou com speed &lt;= 0.
    /// </summary>
    public void SwimTowardsTarget(float speed)
    {
        if (Rb == null || Target == null || speed <= 0f) return;
        Rb.velocity = DirectionToTarget() * speed;
    }

    /// <summary>
    /// Causa "amount" de dano ao player via PlayerCombat.TryDamagePlayer (P2:
    /// respeita i-frames, aplica Defesa da forma e dispara TakeHit com
    /// invencibilidade + knockback). "knockbackDir" só é usado no fallback sem
    /// PlayerCombat.
    /// </summary>
    public void DamagePlayer(int amount, float knockback = 0f, Vector2? knockbackDir = null)
    {
        if (amount <= 0)
        {
            // Só empurrão, sem dano (ex: Attack_Push).
            if (knockback > 0f && Target != null)
            {
                Vector2 dir = knockbackDir ?? ((Vector2)Target.position - (Vector2)transform.position);
                PushPlayer(knockback, dir);
            }
            return;
        }

        PlayerCombat.TryDamagePlayer(Target, amount, transform.position, knockback, knockbackDir);
    }

    /// <summary>Define a velocidade do Rigidbody2D do player como "dir.normalized * force" (empurrão/puxão instantâneo).</summary>
    public void PushPlayer(float force, Vector2 dir)
    {
        if (Target == null || force <= 0f) return;

        var rb = Target.GetComponent<Rigidbody2D>();
        if (rb == null) return;

        Vector2 d = dir.sqrMagnitude > 0.0001f ? dir.normalized : Vector2.right;
        rb.velocity = d * force;
    }

    /// <summary>Alias semântico de <see cref="PushPlayer"/> para ataques que "puxam" o player (ex: anzol — GDD 12.3.5).</summary>
    public void PullPlayer(float force, Vector2 dir) => PushPlayer(force, dir);

    /// <summary>
    /// Imobiliza o player durante "duration" segundos
    /// (PlayerMotor2D.SetMovementLocked — GDD 4.1: "preso por armadilha";
    /// bloqueia também transformação, ver FormSwitcher.TrySwitchTo). Não faz
    /// nada se o alvo não tiver PlayerMotor2D.
    /// </summary>
    public void TrapPlayer(float duration)
    {
        if (Target == null || duration <= 0f) return;

        var motor = Target.GetComponent<PlayerMotor2D>();
        if (motor == null) return;

        StartCoroutine(TrapRoutine(motor, duration));
    }

    private IEnumerator TrapRoutine(PlayerMotor2D motor, float duration)
    {
        // Interrompe qualquer habilidade "com estado" activa (escalar, dash,
        // balanço, língua, escudo, carregar objecto, ...) — item 8 da
        // auditoria: ficar preso a meio de uma destas deixava-a "pendurada"
        // (gravidade/locks não restaurados) durante a armadilha.
        motor.GetComponent<AbilityRouter>()?.CancelAll(AbilityCancelReason.Trapped);

        motor.SetMovementLocked(true, this);
        yield return new WaitForSeconds(duration);
        motor.SetMovementLocked(false, this);
    }

    /// <summary>
    /// Dispara um projéctil configurado por "data" (Etapa 2.2 — ProjectileData),
    /// a partir de transform.position + "spawnOffset", com velocidade inicial
    /// "velocity" (direcção × magnitude — para "Arco", já calculada pelo
    /// EnemyAttack a partir de arcHeight/flightTime).
    ///
    /// Trata "chargeTime" (telegraph com VFX/som), "shotCount"/"fireInterval"
    /// (rajada) e "extraAngles" (leque) — ver ProjectileData. Devolve o
    /// Coroutine correspondente; chamadores normalmente fazem
    /// "yield return ctx.SpawnProjectile(...)" para que o ataque permaneça em
    /// Atacando durante o carregamento + rajada completa. Não faz nada se
    /// "data" for null.
    /// </summary>
    public Coroutine SpawnProjectile(ProjectileData data, Vector2 spawnOffset, Vector2 velocity)
    {
        if (data == null) return null;
        return StartCoroutine(SpawnProjectileRoutine(data, spawnOffset, velocity));
    }

    private IEnumerator SpawnProjectileRoutine(ProjectileData data, Vector2 spawnOffset, Vector2 velocity)
    {
        GameObject chargeVfx = null;

        if (data.chargeTime > 0f)
        {
            if (data.chargeVfxPrefab != null)
                chargeVfx = Instantiate(data.chargeVfxPrefab, transform.position + (Vector3)spawnOffset, Quaternion.identity, transform);

            if (data.chargeSound != null)
                AudioSource.PlayClipAtPoint(data.chargeSound, transform.position);

            yield return new WaitForSeconds(data.chargeTime);

            if (chargeVfx != null) Destroy(chargeVfx);
        }

        if (_controller.IsTerminal) yield break;

        int shots = Mathf.Max(1, data.shotCount);

        for (int i = 0; i < shots; i++)
        {
            FireVolley(data, spawnOffset, velocity);

            if (i < shots - 1 && data.fireInterval > 0f)
                yield return new WaitForSeconds(data.fireInterval);
        }
    }

    /// <summary>Dispara a direcção base + cada um dos "extraAngles" (rotações em graus à volta de "velocity"), num único tiro.</summary>
    private void FireVolley(ProjectileData data, Vector2 spawnOffset, Vector2 velocity)
    {
        SpawnSingleProjectile(data, spawnOffset, velocity);

        if (data.extraAngles != null)
        {
            foreach (float angle in data.extraAngles)
                SpawnSingleProjectile(data, spawnOffset, RotateVector(velocity, angle));
        }
    }

    /// <summary>
    /// Obtém um projéctil de <see cref="ProjectilePool"/> (Tarefa #22 —
    /// reutiliza GameObjects em vez de Instantiate/Destroy) e activa-o em
    /// transform.position + "spawnOffset" com velocidade inicial "velocity".
    /// </summary>
    private void SpawnSingleProjectile(ProjectileData data, Vector2 spawnOffset, Vector2 velocity)
    {
        Vector3 pos = transform.position + (Vector3)spawnOffset;

        var proj = ProjectilePool.Instance.Get(data, pos, Quaternion.identity);
        proj.Activate(data, velocity, Target, _controller);
    }

    /// <summary>Roda "v" por "degrees" graus (sentido anti-horário). Usado para o leque de "extraAngles".</summary>
    private static Vector2 RotateVector(Vector2 v, float degrees)
    {
        float rad = degrees * Mathf.Deg2Rad;
        float cos = Mathf.Cos(rad);
        float sin = Mathf.Sin(rad);
        return new Vector2(cos * v.x - sin * v.y, sin * v.x + cos * v.y);
    }

    /// <summary>
    /// Gizmos de debug (Etapa 7.2): alcance ("range", vermelho) e alcance
    /// mínimo ("minRange", laranja) de cada ataque da lista. Editáveis via
    /// handles no EnemyControllerEditor.
    /// </summary>
    private void OnDrawGizmosSelected()
    {
        if (attacks == null) return;

        foreach (var attack in attacks)
        {
            if (attack == null) continue;

            Gizmos.color = new Color(1f, 0.2f, 0.2f, 0.5f);
            Gizmos.DrawWireSphere(transform.position, attack.range);

            if (attack.minRange > 0f)
            {
                Gizmos.color = new Color(1f, 0.6f, 0.1f, 0.5f);
                Gizmos.DrawWireSphere(transform.position, attack.minRange);
            }
        }
    }

    /// <summary>Distância (no plano XY) entre o ponto "p" e o segmento de recta "a"-"b". Usado por ataques em linha (laser).</summary>
    public static float DistanceToSegment(Vector2 a, Vector2 b, Vector2 p)
    {
        Vector2 ab = b - a;
        float lenSq = ab.sqrMagnitude;

        if (lenSq < 0.0001f) return Vector2.Distance(a, p);

        float t = Mathf.Clamp01(Vector2.Dot(p - a, ab) / lenSq);
        Vector2 projection = a + ab * t;

        return Vector2.Distance(p, projection);
    }
}
